module RefModule(
  input clk,
  input reset,
  output [3:0] count,
  output reg overflow  // Change from wire to reg
);reg [3:0] obf_count_reg;

always @(posedge clk) begin
  if (reset) begin
    obf_count_reg <= 4'b0;
    overflow <= 1'b0;
  end else if (obf_count_reg == 4'b1001) begin
    obf_count_reg <= 4'b0;
    overflow <= 1'b1;
  end else begin
    obf_count_reg <= obf_count_reg + 1;
    overflow <= 1'b0;
  end
end

assign count = obf_count_reg;

endmodule
